PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "shop_id" integer, "branch_id" integer, "name" varchar not null, "email" varchar not null, "phone" varchar, "role" varchar check ("role" in ('owner', 'admin', 'manager', 'cashier')) not null default 'cashier', "email_verified_at" datetime, "password" varchar not null, "is_active" tinyint(1) not null default '1', "remember_token" varchar, "created_at" datetime, "updated_at" datetime, foreign key("shop_id") references "shops"("id") on delete set null, foreign key("branch_id") references "branches"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "shops" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "email" varchar, "phone" varchar, "address" varchar, "logo" varchar, "currency" varchar not null default 'GHS', "currency_symbol" varchar not null default '₵', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "branches" ("id" integer primary key autoincrement not null, "shop_id" integer not null, "name" varchar not null, "address" varchar, "phone" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("shop_id") references "shops"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "shop_id" integer not null, "name" varchar not null, "barcode" varchar, "sku" varchar, "category" varchar, "description" text, "price" numeric not null default '0', "cost" numeric not null default '0', "unit" varchar not null default 'piece', "image" varchar, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("shop_id") references "shops"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "branch_stocks" ("id" integer primary key autoincrement not null, "branch_id" integer not null, "product_id" integer not null, "quantity" numeric not null default '0', "low_stock_alert" numeric not null default '5', "created_at" datetime, "updated_at" datetime, foreign key("branch_id") references "branches"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "customers" ("id" integer primary key autoincrement not null, "shop_id" integer not null, "name" varchar not null, "phone" varchar, "email" varchar, "address" varchar, "credit_limit" numeric not null default '0', "outstanding_balance" numeric not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("shop_id") references "shops"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "sales" ("id" integer primary key autoincrement not null, "reference" varchar not null, "branch_id" integer not null, "user_id" integer not null, "customer_id" integer, "subtotal" numeric not null default '0', "discount" numeric not null default '0', "tax" numeric not null default '0', "total" numeric not null default '0', "amount_paid" numeric not null default '0', "change" numeric not null default '0', "balance_due" numeric not null default '0', "status" varchar check ("status" in ('completed', 'pending', 'cancelled', 'refunded')) not null default 'completed', "payment_status" varchar check ("payment_status" in ('paid', 'partial', 'unpaid')) not null default 'paid', "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("branch_id") references "branches"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, foreign key("customer_id") references "customers"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "sale_items" ("id" integer primary key autoincrement not null, "sale_id" integer not null, "product_id" integer not null, "product_name" varchar not null, "price" numeric not null, "cost" numeric not null default '0', "quantity" numeric not null, "discount" numeric not null default '0', "total" numeric not null, "is_returned" tinyint(1) not null default '0', "returned_quantity" numeric not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("sale_id") references "sales"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "payments" ("id" integer primary key autoincrement not null, "sale_id" integer not null, "customer_id" integer, "method" varchar check ("method" in ('cash', 'mobile_money', 'card', 'credit')) not null default 'cash', "amount" numeric not null, "reference" varchar, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("sale_id") references "sales"("id") on delete cascade, foreign key("customer_id") references "customers"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "expenses" ("id" integer primary key autoincrement not null, "branch_id" integer not null, "user_id" integer not null, "title" varchar not null, "category" varchar not null default 'general', "amount" numeric not null, "notes" text, "expense_date" date not null, "created_at" datetime, "updated_at" datetime, foreign key("branch_id") references "branches"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "activity_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "branch_id" integer, "action" varchar not null, "model_type" varchar, "model_id" integer, "data" text, "ip_address" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null, foreign key("branch_id") references "branches"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "stock_transfers" ("id" integer primary key autoincrement not null, "product_id" integer not null, "from_branch_id" integer not null, "to_branch_id" integer not null, "user_id" integer not null, "quantity" numeric not null, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade, foreign key("from_branch_id") references "branches"("id") on delete cascade, foreign key("to_branch_id") references "branches"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "shop_id" integer not null, "branch_id" integer, "key" varchar not null, "value" text, "type" varchar not null default 'string', "created_at" datetime, "updated_at" datetime, foreign key("shop_id") references "shops"("id") on delete cascade, foreign key("branch_id") references "branches"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "purchase_orders" ("id" integer primary key autoincrement not null, "reference" varchar not null, "shop_id" integer not null, "branch_id" integer not null, "created_by" integer not null, "approved_by" integer, "supplier_name" varchar, "supplier_phone" varchar, "notes" text, "status" varchar check ("status" in ('draft', 'pending', 'approved', 'rejected', 'partial', 'received')) not null default 'draft', "approved_at" datetime, "expected_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("shop_id") references "shops"("id") on delete cascade, foreign key("branch_id") references "branches"("id") on delete cascade, foreign key("created_by") references "users"("id") on delete cascade, foreign key("approved_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "purchase_order_items" ("id" integer primary key autoincrement not null, "purchase_order_id" integer not null, "product_id" integer not null, "product_name" varchar not null, "quantity_requested" numeric not null, "quantity_received" numeric not null default '0', "unit_cost" numeric not null default '0', "status" varchar check ("status" in ('pending', 'received', 'partial', 'missing')) not null default 'pending', "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("purchase_order_id") references "purchase_orders"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "licenses" ("id" integer primary key autoincrement not null, "license_key" varchar not null, "plan_name" varchar, "plan_slug" varchar, "status" varchar check ("status" in ('active', 'expired', 'invalid', 'suspended')) not null default 'active', "activated_at" datetime, "expires_at" datetime, "verified_at" datetime, "verification_token" varchar, "days_remaining" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "license_plans" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "duration_days" integer not null, "price" numeric not null, "currency" varchar not null default 'GHS', "created_at" datetime, "updated_at" datetime, "is_active" tinyint(1) not null default '1');
CREATE TABLE IF NOT EXISTS "license_verifications" ("id" integer primary key autoincrement not null, "license_id" integer not null, "ip_address" varchar, "domain" varchar, "success" tinyint(1) not null default '0', "verified_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("license_id") references "licenses"("id") on delete cascade);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "shops_slug_unique" on "shops" ("slug");
CREATE INDEX "products_barcode_index" on "products" ("barcode");
CREATE UNIQUE INDEX "branch_stocks_branch_id_product_id_unique" on "branch_stocks" ("branch_id", "product_id");
CREATE UNIQUE INDEX "sales_reference_unique" on "sales" ("reference");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE UNIQUE INDEX "settings_shop_id_branch_id_key_unique" on "settings" ("shop_id", "branch_id", "key");
CREATE UNIQUE INDEX "purchase_orders_reference_unique" on "purchase_orders" ("reference");
CREATE UNIQUE INDEX "licenses_license_key_unique" on "licenses" ("license_key");
CREATE UNIQUE INDEX "license_plans_slug_unique" on "license_plans" ("slug");
COMMIT;
